final:
module RefModule(
    input wire clk,
    input wire load,
    input wire [7:0] data,
    output wire q
);

reg [7:0] obf_register;

always @(posedge clk) begin
    if (load)
        obf_register <= data;
    else
        obf_register <= obf_register >> 1;
end

assign q = obf_register[0];

endmodule
